func TestNewPolicyQuotaController(t *testing.T) {
	mockResource := NewMockResource()
	controller := NewPolicyQuotaController(nil, mockResource, 10)

	if controller == nil {
		t.Fatal("Expected non-nil controller")
	}
	if controller.maxPerNamespace != 10 {
		t.Fatalf("Expected maxPerNamespace=10, got %d", controller.maxPerNamespace)
	}
}

func TestCheckQuotaUnderLimit(t *testing.T) {
	mockResource := NewMockResource()
	controller := NewPolicyQuotaController(logging.DefaultLogger, mockResource, 10)

	// Initially no policies, should pass quota check
	err := controller.CheckQuota("test-ns")
	if err != nil {
		t.Fatalf("Expected no error for new namespace, got: %v", err)
	}
}

func TestCheckQuotaExceeded(t *testing.T) {
	mockResource := NewMockResource()
	controller := NewPolicyQuotaController(logging.DefaultLogger, mockResource, 5)

	// Manually set policy count to maximum
	controller.policyCountMutex.Lock()
	controller.policyCount["test-ns"] = 5
	controller.policyCountMutex.Unlock()

	// Should fail quota check
	err := controller.CheckQuota("test-ns")
	if err == nil {
		t.Fatal("Expected error for quota exceeded, got nil")
	}
}

func TestOnPolicyUpsert(t *testing.T) {
	mockResource := NewMockResource()
	controller := NewPolicyQuotaController(logging.DefaultLogger, mockResource, 10)

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	err := controller.onPolicyUpsert(policy)
	if err != nil {
		t.Fatalf("Unexpected error on upsert: %v", err)
	}

	count := controller.GetNamespaceCount("test-ns")
	if count != 1 {
		t.Fatalf("Expected count=1, got %d", count)
	}

	// Upsert again (simulates update)
	err = controller.onPolicyUpsert(policy)
	if err != nil {
		t.Fatalf("Unexpected error on second upsert: %v", err)
	}

	count = controller.GetNamespaceCount("test-ns")
	if count != 2 {
		t.Fatalf("Expected count=2 after second upsert, got %d", count)
	}
}

func TestOnPolicyDelete(t *testing.T) {
	mockResource := NewMockResource()
	controller := NewPolicyQuotaController(logging.DefaultLogger, mockResource, 10)

	policy := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	// Add a policy
	controller.onPolicyUpsert(policy)
	if count := controller.GetNamespaceCount("test-ns"); count != 1 {
		t.Fatalf("Expected count=1 after upsert, got %d", count)
	}

	// Delete the policy
	err := controller.onPolicyDelete(policy)
	if err != nil {
		t.Fatalf("Unexpected error on delete: %v", err)
	}

	count := controller.GetNamespaceCount("test-ns")
	if count != 0 {
		t.Fatalf("Expected count=0 after delete, got %d", count)
	}

	// Verify namespace is removed from map
	controller.policyCountMutex.RLock()
	_, exists := controller.policyCount["test-ns"]
	controller.policyCountMutex.RUnlock()
	if exists {
		t.Fatalf("Expected namespace to be removed from map")
	}
}

func TestGetNamespaceCount(t *testing.T) {
	mockResource := NewMockResource()
	controller := NewPolicyQuotaController(logging.DefaultLogger, mockResource, 10)

	policy1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy1",
			Namespace: "ns1",
		},
	}

	policy2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy2",
			Namespace: "ns2",
		},
	}

	controller.onPolicyUpsert(policy1)
	controller.onPolicyUpsert(policy2)

	count1 := controller.GetNamespaceCount("ns1")
	if count1 != 1 {
		t.Fatalf("Expected count=1 for ns1, got %d", count1)
	}

	count2 := controller.GetNamespaceCount("ns2")
	if count2 != 1 {
		t.Fatalf("Expected count=1 for ns2, got %d", count2)
	}
}

